import{_ as t,o,c as a,a2 as c}from"./chunks/framework.Crpw6aS5.js";const h=JSON.parse('{"title":"投资决策","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-scene/投资决策.md","filePath":"05_quotes/by-scene/投资决策.md"}'),r={name:"05_quotes/by-scene/投资决策.md"};function l(n,e,u,s,q,_){return o(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="投资决策" tabindex="-1">投资决策 <a class="header-anchor" href="#投资决策" aria-label="Permalink to &quot;投资决策&quot;">​</a></h1><blockquote><p>&quot;投资的全部意义在于，在好公司以合理价格买入。但合理价格远低于内在价值时买入，就是安全边际。&quot;——巴菲特</p></blockquote><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;要进行成功的投资，您不需要理解贝塔系数、有效市场、现代投资组合理论、期权定价或新兴市场。事实上，您可能对这些一无所知反而更好。&quot;</p></blockquote><blockquote><p>&quot;投资就像滚雪球，你只需要找到很湿的雪和很长的坡道。复利会为愿意等待的人工作。&quot;</p></blockquote><blockquote><p>&quot;我们选择可交易股权的方法，和我们评估整体收购企业时一模一样：业务好理解，有长期前景，由诚实能干的人运营，价格有吸引力。&quot;</p></blockquote><blockquote><p>&quot;你不需要知道一个人的精确年龄才能知道他有投票权，也不需要知道他的确切体重才能认出他需要节食。投资也是如此：模糊的正确好过精确的错误。&quot;</p></blockquote><blockquote><p>&quot;如果它们的业务表现持续让我们满意，我们甚至欢迎我们持有的股票市场价格下跌，这样我们就能以更好的价格买到更多。&quot;</p></blockquote><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><p><a href="/02_concepts/intrinsic-value.html">内在价值</a> · <a href="/02_concepts/safety-margin.html">安全边际</a> · <a href="/02_concepts/circle-of-competence.html">能力圈</a> · <a href="/02_concepts/contrarian.html">逆向思维</a> · <a href="/02_concepts/long-term.html">长期主义</a></p>',12)])])}const i=t(r,[["render",l]]);export{h as __pageData,i as default};
